testcase.Script:
var hsms = this.ta.get("/api/hsms");

for (var i = 0; i < hsms.length; i++) {
	this.assertTrue(hsms[i].id, "Must return a list of hsms");

	var keys = this.ta.get("/api/hsms/" + hsms[i].id + "/keys");

	for (var j = 0; j < keys.length; j++) {
		this.assertTrue(keys[j].id, "Must return a list of keys");

		var kref = "/api/hsms/" + hsms[i].id + "/keys/" + keys[j].id;
		var key = this.ta.get(kref);

		this.assertTrue(key.id, "Must return a single key entry");

		var pk = undefined;
		if (key.cert) {
			var bin = new ByteString(key.cert, BASE64);
			if (bin.byteAt(0) == 0x30) {
				var cert = new X509(bin);
			} else {
				var cert = new CVC(bin);
			}
			pk = cert.getPublicKey();
		}

		var message = new ByteString("Hello World", ASCII);
		var hash = this.parameter.crypto.digest(Crypto.SHA_256, message);

		var inp = {
			hash: hash.toString(HEX)
		};

		if (key.type == "EC") {
			inp.algo = "ECDSA";
			var sig = this.ta.post(kref + "/signhash", inp);

			if (pk) {
				this.assertTrue(this.parameter.crypto.verify(pk, Crypto.ECDSA, hash, new ByteString(sig.signature, HEX)), "Signature verification failed");
			}
		} else if (key.type == "RSA") {
			inp.algo = "RSA_PKCS1";
			var sig = this.ta.post(kref + "/signhash", inp);

			if (pk) {
				this.assertTrue(this.parameter.crypto.verify(pk, Crypto.RSA_SHA256, message, new ByteString(sig.signature, HEX)), "Signature verification failed");
			}

			inp.algo = "RSA_PSS";
			var sig = this.ta.post(kref + "/signhash", inp);

			if (pk) {
				this.assertTrue(this.parameter.crypto.verify(pk, Crypto.RSA_PSS_SHA256, message, new ByteString(sig.signature, HEX)), "Signature verification failed");
			}
		}
	}
}

var keys = this.ta.get("/api/keys");

for (var i = 0; i< keys.length; i++) {
	this.assertTrue(keys[i].id, "Must return a list of keys");

	var kref = "/api/keys/" + keys[i].id;

	var key = this.ta.get(kref);
	this.assertTrue(key.id, "Must return a single key entry");

	var pk = undefined;
	if (key.cert) {
		var bin = new ByteString(key.cert, BASE64);
		if (bin.byteAt(0) == 0x30) {
			var cert = new X509(bin);
		} else {
			var cert = new CVC(bin);
		}
		pk = cert.getPublicKey();
	}

	var message = new ByteString("Hello World", ASCII);
	var hash = this.parameter.crypto.digest(Crypto.SHA_256, message);

	var inp = {
		hash: hash.toString(HEX)
	};

	if (key.type == "EC") {
		inp.algo = "ECDSA";
		var sig = this.ta.post(kref + "/signhash", inp);

		if (pk) {
			this.assertTrue(this.parameter.crypto.verify(pk, Crypto.ECDSA, hash, new ByteString(sig.signature, HEX)), "Signature verification failed");
		}
	} else if (key.type == "RSA") {
		inp.algo = "RSA_PKCS1";
		var sig = this.ta.post(kref + "/signhash", inp);

		if (pk) {
			this.assertTrue(this.parameter.crypto.verify(pk, Crypto.RSA_SHA256, message, new ByteString(sig.signature, HEX)), "Signature verification failed");
		}

		inp.algo = "RSA_PSS";
		var sig = this.ta.post(kref + "/signhash", inp);

		if (pk) {
			this.assertTrue(this.parameter.crypto.verify(pk, Crypto.RSA_PSS_SHA256, message, new ByteString(sig.signature, HEX)), "Signature verification failed");
		}
	}
}

